import { FormattedMessage } from 'react-intl';

import { MagnifyingGlassIcon, PasteIcon } from '@dynatrace/strato-icons';

import * as styles from '../../FilterField.sty.js';
import { filterFieldMessages } from '../../messages.js';
import * as suggestionStyles from '../../suggestions/Suggestion.sty.js';
import type {
  FilterFieldSuggestion,
  FilterFieldSuggestionProps,
} from '../../suggestions/Suggestion.types.js';
import type {
  FilterFieldComparisonOperators,
  FilterFieldPrimitive,
} from '../../types/validation.js';
import { escapeSuggestion } from '../escape-suggestion.js';
import { getOperatorShortName } from '../validation-utils/operator-specification.js';

/**
 * @internal
 */
export function getNoMatchingSuggestion(
  valueType: FilterFieldPrimitive = 'Any',
): FilterFieldSuggestion {
  return {
    trailing: '',
    valueType,
    displayValue: (
      <FormattedMessage
        {...filterFieldMessages.suggestions.noMatchingSuggestions}
      />
    ),
  };
}

/**
 * @internal
 */
export function getStartTypingSuggestion(
  suggestionType: 'key' | 'value' | 'search phrase',
  valueType: FilterFieldPrimitive | string = 'Any',
): FilterFieldSuggestion {
  return {
    trailing: '',
    valueType,
    suggestionType: 'hint-startTyping',
    displayValue: (
      <FormattedMessage
        {...filterFieldMessages.suggestions.startTyping}
        values={{
          suggestionType,
        }}
      />
    ),
  };
}

/**
 * @internal
 */
export function getPastingSuggestion(
  valueType: FilterFieldPrimitive = 'Any',
): FilterFieldSuggestionProps & {
  [key: `data-strato-filter-field-${string}`]: boolean;
} {
  return {
    trailing: '',
    valueType,
    suggestionType: 'pastedContent',
    id: 'strato-filterfield-suggestion-pasted-content',
    icon: <PasteIcon />,
    displayValue: (
      <FormattedMessage {...filterFieldMessages.suggestions.pasteRaw} />
    ),
    'data-strato-filter-field-should-escape-suggestion': true,
  };
}

/** @internal */
export function getSearchSuggestion(
  value?: string,
): FilterFieldSuggestionProps {
  if (value === undefined) {
    return {
      value: '* ~ "',
      trailing: '"',
      cursorBeforeTrailing: true,
      id: 'strato-filterfield-suggestion-search',
      displayValue: (
        <FormattedMessage
          {...filterFieldMessages.suggestions.search}
          values={{
            value: false,
          }}
        />
      ),
      icon: <MagnifyingGlassIcon />,
      insertionStrategy: 'replace-statement',
    };
  }

  // Check if the value starts with a quote and ends with a quote followed by a space.
  const match = /^"(.+)(?<!\\)" ?$/.exec(value);
  const textValue = match ? match[1] : value;
  const escapedSuggestion = escapeSuggestion(match ? value.trim() : value);

  return {
    value: `* ~ ${escapedSuggestion}`,
    id: 'strato-filterfield-suggestion-search',
    displayValue: (
      <FormattedMessage
        {...filterFieldMessages.suggestions.search}
        values={{
          value: (
            <>
              &nbsp;
              <mark>{textValue}</mark>
            </>
          ),
        }}
      />
    ),
    icon: <MagnifyingGlassIcon />,
    insertionStrategy: 'replace-statement',
  };
}

/** @internal */
export function getFallbackKeySuggestion(
  key: string,
  operator: FilterFieldComparisonOperators,
  value: string,
): FilterFieldSuggestionProps {
  // Check if the value starts with a quote and ends with a quote followed by a space.
  const match = /^"(.+)(?<!\\)" ?$/.exec(value);
  const textValue = match ? match[1] : value;
  const escapedSuggestion = escapeSuggestion(match ? value.trim() : value);
  const baseOperator = operator.includes('not') ? '!=' : '='; // needed for the wildcard operators

  switch (operator) {
    case 'in':
    case 'not in': {
      return {
        value: `${key} ${operator} (${escapedSuggestion})`,
        displayValue: (
          <span>
            {key} {operator} (<mark>{textValue}</mark>)
          </span>
        ),
        insertionStrategy: 'replace-statement',
      };
    }
    case 'contains':
    case 'not-contains': {
      return {
        value: `${key} ${baseOperator} *${escapedSuggestion}*`,
        displayValue: (
          <span>
            {key} {baseOperator} *<mark>{textValue}</mark>*
          </span>
        ),
        insertionStrategy: 'replace-statement',
      };
    }
    case 'starts-with':
    case 'not-starts-with': {
      return {
        value: `${key} ${baseOperator} ${escapedSuggestion}*`,
        displayValue: (
          <span>
            {key} {baseOperator} <mark>{textValue}</mark>*
          </span>
        ),
        insertionStrategy: 'replace-statement',
      };
    }
    case 'ends-with':
    case 'not-ends-with': {
      return {
        value: `${key} ${baseOperator} *${escapedSuggestion}`,
        displayValue: (
          <span>
            {key} {baseOperator} *<mark>{textValue}</mark>
          </span>
        ),
        insertionStrategy: 'replace-statement',
      };
    }
    default: {
      const operatorName = getOperatorShortName(operator);

      return {
        value: `${key} ${operatorName} ${escapedSuggestion}`,
        displayValue: (
          <span>
            {key} {operatorName} <mark>{textValue}</mark>
          </span>
        ),
        insertionStrategy: 'replace-statement',
      };
    }
  }
}

/** @internal */
export function getStatementSuggestionForMatchingValue(
  key: string,
  value: string,
): FilterFieldSuggestionProps {
  const match = /^"(.+)(?<!\\)" ?$/.exec(value);
  const textValue = match ? match[1] : value;
  const escapedSuggestion = escapeSuggestion(match ? value.trim() : value);

  return {
    value: `${key} = ${escapedSuggestion}`,
    // Add the class only to the value part as we only want to show highlighting in the value and not the key
    displayValue: (
      <span>
        {key} ={' '}
        <span className={suggestionStyles.statementSuggestionValue}>
          {textValue}
        </span>
      </span>
    ),
    insertionStrategy: 'replace-statement',
  };
}

/**
 * @internal
 */
export function getJSONPathHint(): FilterFieldSuggestionProps {
  return {
    trailing: '',
    id: 'strato-filterfield-suggestion-jsonpath-hint',
    suggestionType: 'JSONPath',
    displayValue: (
      <span className={styles.suggestionHintContainer}>
        <FormattedMessage
          defaultMessage="Filter JSON attributes using dot notation. For example: "
          description="Hint for entering JSONPath syntax in the FilterField."
          id="Ua7PnIRWAcErpii9"
        />
        <span className={styles.filterStatementBase}>
          <span className={styles.filterKey}>content$.key[1].key </span>
          <span className={styles.operator}>=</span>{' '}
          <span className={styles.filterValue}>value</span>
        </span>
      </span>
    ),
  };
}
